section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "testing-javascript-output",
  "required": [
    "runner",
    "config_file",
    "environment",
    "coverage_threshold",
    "forbidden_seen"
  ],
  "properties": {
    "runner": {
      "description": "Chosen runner."
    },
    "config_file": {
      "description": "Path to runner config."
    },
    "environment": {
      "description": "Test environment per file or globally."
    },
    "coverage_threshold": {
      "description": "Lines/branches/functions/statements thresholds."
    },
    "msw_version": {
      "description": "MSW version if API mocking used."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
